const response = $.steps.listDriveFiles.response;
const files = response.files || response.data || [];

const fileList = [];
let compiled = '';

if (Array.isArray(files)) {
  files.slice(0, 15).forEach((f, i) => {
    fileList.push({
      index: i + 1,
      id: f.id || '',
      name: f.name || 'Untitled',
      mimeType: f.mimeType || 'unknown',
      modifiedTime: f.modifiedTime || '',
      size: f.size || 'N/A',
      description: f.description || ''
    });

    compiled += 'FILE ' + (i + 1) + ': ' + (f.name || 'Untitled') + '\n';
    compiled += '  Type: ' + (f.mimeType || 'unknown') + '\n';
    compiled += '  Modified: ' + (f.modifiedTime || 'N/A') + '\n';
    compiled += '  Size: ' + (f.size || 'N/A') + ' bytes\n';
    if (f.description) compiled += '  Description: ' + f.description.slice(0, 200) + '\n';
    compiled += '\n';
  });
}

return { fileList, compiled, fileCount: fileList.length };

const d = $.steps.compileFileData.output;
const fileTypes = $.input.fileTypes || 'documents and spreadsheets';

let prompt = 'You are a document analysis and summarization specialist. Analyze the following list of Google Drive files and create comprehensive summaries suitable for a Notion knowledge base.\n\n';
prompt += 'FILE TYPES OF INTEREST: ' + fileTypes + '\n';
prompt += 'TOTAL FILES: ' + d.fileCount + '\n\n';
prompt += 'FILES FROM GOOGLE DRIVE:\n' + d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- For each relevant file, create a summary based on the filename, type, and any available metadata\n';
prompt += '- Categorize files by type (documents, spreadsheets, presentations, etc.)\n';
prompt += '- Suggest what each file likely contains based on its name\n';
prompt += '- Identify files that may be related or part of a project\n';
prompt += '- Each section content MUST be under 1900 characters (Notion API limit)\n';
prompt += '- Create an organized summary suitable for a Notion page\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "Drive Files Summary - [date]",\n';
prompt += '  "overallSummary": "2-3 sentence overview of the files (under 1900 chars)",\n';
prompt += '  "categories": [\n';
prompt += '    {\n';
prompt += '      "name": "category name",\n';
prompt += '      "files": [\n';
prompt += '        { "fileName": "name", "summary": "what this file likely contains (under 1900 chars)", "relevance": "high|medium|low" }\n';
prompt += '      ]\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "relatedGroups": [{ "groupName": "project name", "files": ["file1", "file2"], "relationship": "how related" }],\n';
prompt += '  "actionItems": ["suggested action based on files"],\n';
prompt += '  "totalFilesAnalyzed": 0\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Drive Files Summary', overallSummary: raw.slice(0, 1900), categories: [], relatedGroups: [], actionItems: [], totalFilesAnalyzed: 0 }; }

const ai = $.steps.parseAI.output;
const blocks = [];

if (ai.overallSummary) {
  const summaryText = ai.overallSummary.slice(0, 1900);
  blocks.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ text: { content: summaryText } }] } });
  blocks.push({ object: 'block', type: 'divider', divider: {} });
}

(ai.categories || []).forEach(cat => {
  blocks.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ text: { content: (cat.name || 'Files').slice(0, 1900) } }] } });
  (cat.files || []).forEach(file => {
    const fileText = (file.fileName || 'Unknown') + ': ' + (file.summary || 'No summary');
    const chunks = [];
    let remaining = fileText;
    while (remaining.length > 0) {
      chunks.push(remaining.slice(0, 1900));
      remaining = remaining.slice(1900);
    }
    chunks.forEach(chunk => {
      blocks.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ text: { content: chunk } }] } });
    });
  });
});

if (ai.relatedGroups && ai.relatedGroups.length > 0) {
  blocks.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ text: { content: 'Related File Groups' } }] } });
  ai.relatedGroups.forEach(group => {
    const groupText = (group.groupName || 'Group') + ': ' + (group.files || []).join(', ') + ' - ' + (group.relationship || '');
    blocks.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ text: { content: groupText.slice(0, 1900) } }] } });
  });
}

if (ai.actionItems && ai.actionItems.length > 0) {
  blocks.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ text: { content: 'Action Items' } }] } });
  ai.actionItems.forEach(item => {
    blocks.push({ object: 'block', type: 'to_do', to_do: { rich_text: [{ text: { content: item.slice(0, 1900) } }], checked: false } });
  });
}

return { blocks: blocks.slice(0, 95), title: ai.title || 'Drive Files Summary', totalFiles: ai.totalFilesAnalyzed || 0 };

const ai = $.steps.parseAI.output;
const pageResponse = $.steps.createNotionPage.response || {};
const pageUrl = pageResponse.url || '';
const title = $.steps.buildNotionBlocks.output.title;
const fileCount = $.steps.compileFileData.output.fileCount;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Drive File Summary Saved to Notion', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Files Analyzed:*\n' + fileCount },
  { type: 'mrkdwn', text: '*Categories:*\n' + (ai.categories || []).length }
] });

if (ai.overallSummary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:* ' + ai.overallSummary.slice(0, 1800) } });
}

if (pageUrl) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':link: <' + pageUrl + '|View in Notion>' } });
}

if (ai.actionItems && ai.actionItems.length > 0) {
  blocks.push({ type: 'divider' });
  let actionText = '*Action Items:*\n';
  ai.actionItems.slice(0, 5).forEach((a, i) => { actionText += (i + 1) + '. ' + a + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: actionText.slice(0, 1800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Drive + Claude AI + Notion | One CLI' }] });

const fallback = 'Drive Summary: ' + fileCount + ' files analyzed, saved to Notion';
return { blocks, fallback };
